var suggestions=document.getElementById('suggestions'),search=document.getElementById('search');search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(b){const d=suggestions.querySelectorAll('a'),e=[...d],a=e.indexOf(document.activeElement),f=suggestions.classList.contains('d-none');let c=0;b.keyCode===38&&!f?(b.preventDefault(),c=a>0?a-1:0,d[c].focus()):b.keyCode===40&&!f&&(b.preventDefault(),c=a+1<e.length?a+1:a,d[c].focus())}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description","content"]}});a.add({id:0,href:"/en/docs/edu/uni-paris/",title:"Université de Paris",description:"September 2021 to September 2022 - Master's degree in multingual technical communication (CTM)",content:'\u003cimg src="../../paris_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:69px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description"\u003eDescription\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eBilingual Master\u0026rsquo;s degree (EN/FR) and apprenticeship (2 weeks at a company / 2 weeks at university).\n\u003cul\u003e\n\u003cli\u003eCourses in technical writing, in its technologies (DITA), introduction to e-learning.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n'}).add({id:1,href:"/en/docs/edu/uni-rennes/",title:"Université Rennes 2",description:"September 2018 to September 2020 - Master's degree in translation",content:'\u003cimg src="../../rennes2_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:69px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description"\u003eDescription\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eEuropean Master\u0026rsquo;s in Translation - Translation, localization and project management.\n\u003cul\u003e\n\u003cli\u003eCourses in technical translation, localization, in their tools (CAT) as well as project management.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n'}).add({id:2,href:"/en/docs/portfolio/geoguessr/",title:"Geoguessr",description:"",content:'\u003cdiv class="alert alert-warning d-flex" role="alert"\u003e\r\n  \u003cdiv class="flex-shrink-1 alert-icon"\u003e⚠️ \u003c/div\u003e\r\n  \r\n    \r\n      \u003cdiv class="w-100"\u003e This guide was originally written in DITA, then transformed to Markdown through the \u003ca href="https://github.com/dita-ot/dita-ot"\u003eDITA Open Toolkit\u003c/a\u003e. As a result, it may contain errors.\u003cbr/\u003e\u003cbr/\u003eThank you for your understanding.\u003c/div\u003e\r\n    \r\n  \r\n\u003c/div\u003e\r\n\n\u003ch2 id="introduction"\u003eIntroduction\u003c/h2\u003e\n\u003cimg src="../../geoguessr_logo.png" alt="Grapefruit slice atop a pile of other slices"\u003e\n\u003cbr/\u003e\n\u003cp\u003eWelcome to How to master Geoguessr \u0026ndash;or where the heck am I?!\u003c/p\u003e\n\u003cp\u003eThrough this hopefully thorough guide, I wish to introduce you to a wonderful game called Geoguessr. May this lecture help you master it.\u003c/p\u003e\n\u003ch3 id="group-introduction"\u003eGroup introduction\u003c/h3\u003e\n\u003cp\u003eMastering Video Games is a technical documentation group, made out of five students from Université de Paris.\u003c/p\u003e\n\u003cp\u003eOur names are Dorian Baret, Néda El Hadj Mimoune, Andréï Georgescu, Samy Oubouaziz, and Mélissa Stocchi.\u003c/p\u003e\n\u003cp\u003eWe are all part of the CTM (Multingual Technical Communication) Master\u0026rsquo;s Degree, lead by Professor Patricia Minacori.\u003c/p\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../logo.png" alt="Logo for Mastering Video Games" style="align-content: center;"\u003e\u003c/div\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../us.png" alt="The members of Mastering Video Games"\u003e\u003c/div\u003e\n\u003ch3 id="legal-disclaimer"\u003eLegal disclaimer\u003c/h3\u003e\n\u003cp\u003eCopyright © 2022, Mastering Video Games, all rights reserved. All the information on our guides is published in good faith and for general information purpose only. We do not make any warranties about the completeness, reliability and accuracy of this information. Any action you take upon the information you find in these guides is strictly at your own risk. We will not be liable for any losses and/or damages in connection with the use of our guides.\u003c/p\u003e\n\u003ch2 id="what-is-geoguessr"\u003eWhat is Geoguessr?\u003c/h2\u003e\n\u003cp\u003eGeoguessr is an online video game, which takes its player around the world, challenging them to find where they are through the lens of an interactive Panorama.\u003c/p\u003e\n\u003cp\u003eIn its paid version, the game uses imagery from Google Street View, a feature of Google Maps, that provides interactive Panoramas from positions along many streets in the world. Most photography is done by car, but some is done by tricycle, boat, snowmobile, and underwater apparatus, as well as on foot. Individuals can also submit their Photo Spheresto the service.\u003c/p\u003e\n\u003cp\u003eIn its free version, the game uses imagery from Mapillary, a competitor of Google Street View.\u003c/p\u003e\n\u003ch3 id="and-what-modes-can-you-play"\u003eAnd, what modes can you play?\u003c/h3\u003e\n\u003cp\u003eAs a free player, only Classic mode is available.As a Pro player, many modes of play are available.\u003c/p\u003e\n\u003cp\u003eConsult the Pro guide for more information about Pro game modes.\u003c/p\u003e\n\u003cp\u003eThere are that many modes of play available to a Pro player:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eClassic mode\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eExplorer mode\u003c/li\u003e\n\u003cli\u003eStreaks\u003c/li\u003e\n\u003cli\u003eThe Daily Challenge\u003c/li\u003e\n\u003cli\u003ePro Leagues\u003c/li\u003e\n\u003cli\u003eMap Maker\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003ePlay with Friends (allows the players to do the other modes with other people)\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eCareer\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eBattle Royale\u003c/li\u003e\n\u003cli\u003eBattle Royale Distance\u003c/li\u003e\n\u003cli\u003eBattle Royale Countries\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch3 id="so-how-much-does-geoguessr-cost"\u003eSo, how much does Geoguessr cost?\u003c/h3\u003e\n\u003cp\u003eGeoguessr is a freemium game and an example of games as a service (GaaS).\u003c/p\u003e\n\u003ch4 id="playing-pro-geoguessr"\u003ePlaying Pro Geoguessr\u003c/h4\u003e\n\u003cp\u003eGeoguessr, as a freemium, offers most of its features to Pro players.\u003c/p\u003e\n\u003cp\u003eThe free version of Geoguessr offers limited features in comparison to its Pro version:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eLower quality of images.\u003c/p\u003e\n\u003cp\u003eThe source of the free version is Mapillary, which offers a service similar to Google Street View but more limited.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="playing-geoguessr-for-free"\u003ePlaying Geoguessr for free\u003c/h4\u003e\n\u003cp\u003eGeoguessr, as a freemium, offers basic features for free.\u003c/p\u003e\n\u003cp\u003eThe free version of Geoguessr offers limited features in comparison to its Pro version:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eLower quality of images.\u003c/p\u003e\n\u003cp\u003eThe source of the free version is Mapillary, which offers a service similar to Google Street View but more limited.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eMapillary view often lack the possibility of moving.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eA game of Geoguessr is five rounds long.\u003c/p\u003e\n\u003cp\u003eWith the free version, at the 3rd round, the game is interrupted for 10 seconds by a prompt to subscribe to the Pro version.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eThe user is limited to one Map: \u0026ldquo;World\u0026rdquo;.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="where-the-heck-am-i"\u003eWhere the heck am I?!\u003c/h2\u003e\n\u003cp\u003eMapping the world is a colossal task. Hence, Google Street View offers a limited range of destinations.Hence, Mapillary offers a limited range of destinations, which is also lower than of Google.\u003c/p\u003e\n\u003ch3 id="exploring-the-interface"\u003eExploring the interface\u003c/h3\u003e\n\u003cp\u003eLet\u0026rsquo;s familiarize ourselves with the Geoguessr interface.\u003c/p\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../ui.png" alt="Geoguessr interface"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eIn the image below, you will see the Geoguessr interface divided in six zones. Let\u0026rsquo;s give them names:\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#controls"\u003eControls\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#compass"\u003eCompass\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#status"\u003eStatus\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#map"\u003eMap\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#panorama"\u003ePanorama\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003e\u003ca href="#arrows"\u003eMovement arrows\u003c/a\u003e\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch4 id="controls-a-idcontrols"\u003eControls \u003ca id="controls"/\u003e\u003c/h4\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../controls.png" alt="Geoguessr Controls"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eThe Controls have multiple purposes:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eThe \u003cimg src="../../zoom_in.png"\u003e allows the player to zoom in in the Panorama. The \u003cimg src="../../zoom_out.png"\u003e allows the player to zoom out in the Panorama.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eThe \u003cimg src="../../options.png"\u003e allows the player to access the \u003cstrong\u003eOptions\u003c/strong\u003e.\u003c/p\u003e\n\u003cp\u003eInside, the \u003cstrong\u003eEffect volume\u003c/strong\u003e and the \u003cstrong\u003eMusic volume\u003c/strong\u003e can be controlled by sliders. The \u003cstrong\u003eSound\u003c/strong\u003e, \u003cstrong\u003eClassic Compass\u003c/strong\u003e and \u003cstrong\u003eFullscreen\u003c/strong\u003e can be turned \u003cstrong\u003eON\u003c/strong\u003e or \u003cstrong\u003eOFF\u003c/strong\u003e through switches.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eThe \u003cimg src="../../return_to_start.png"\u003e allows the player to \u003cstrong\u003eReturn to start\u003c/strong\u003e.\u003c/p\u003e\n\u003cp\u003eIt can also be triggered by pressing \u003cstrong\u003eR\u003c/strong\u003e anytime during a game.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eThe \u003cimg src="../../set_checkpoint.png"\u003e allows the player to \u003cstrong\u003eSet checkpoint\u003c/strong\u003e.\u003c/p\u003e\n\u003cp\u003eIt can also be triggered by pressing \u003cstrong\u003eC\u003c/strong\u003e anytime during a game.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eAfter it is clicked, \u003cimg src="../../return_to_checkpoint.png"\u003e appears and allows the player to \u003cstrong\u003eReturn to checkpoint\u003c/strong\u003e.\u003c/p\u003e\n\u003cp\u003eIt can also be triggered by pressing \u003cstrong\u003eC\u003c/strong\u003e, once a checkpoint has been set.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eThe \u003cimg src="../../undo_move.png"\u003e allows the player to \u003cstrong\u003eUndo move\u003c/strong\u003e.\u003c/p\u003e\n\u003cp\u003eIt can also be triggered by pressing \u003cstrong\u003eZ\u003c/strong\u003e anytime during a game, provided the player has made a move since the beginning of the round. If the player hasn\u0026rsquo;t made, it\u0026rsquo;s greyed out.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="compass-a-idcompass"\u003eCompass \u003ca id="compass"/\u003e\u003c/h4\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../compass.png" alt="Geoguessr Compass"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eThe Compass automatically displays in its center the orientation of the player view, as they move through the Panorama. By default, at the beginning of each round, the player faces North.\u003c/p\u003e\n\u003cdiv class="alert alert-warning d-flex" role="alert"\u003e\r\n  \u003cdiv class="flex-shrink-1 alert-icon"\u003e⚠️ \u003c/div\u003e\r\n  \r\n    \u003cdiv class="w-100"\u003eAlthough the Compass can be a crucial tool, beware the type of Panorama, for example: the orientation of Photo Spheres is often wrong. \u003c/div\u003e\r\n  \r\n\u003c/div\u003e\r\n\n\u003ctable\u003e\n\u003cthead\u003e\n\u003ctr\u003e\n\u003cth\u003eAbbreviation\u003c/th\u003e\n\u003cth\u003eFull term\u003c/th\u003e\n\u003c/tr\u003e\n\u003c/thead\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003eN\u003c/td\u003e\n\u003ctd\u003eNorth\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eS\u003c/td\u003e\n\u003ctd\u003eSouth\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eW\u003c/td\u003e\n\u003ctd\u003eWest\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eE\u003c/td\u003e\n\u003ctd\u003eEast\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eNW\u003c/td\u003e\n\u003ctd\u003eNorth-west\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eSW\u003c/td\u003e\n\u003ctd\u003eSouth-west\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eSE\u003c/td\u003e\n\u003ctd\u003eSouth-east\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003eNE\u003c/td\u003e\n\u003ctd\u003eNorth-east\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ch4 id="status-a-idstatus"\u003eStatus \u003ca id="status"/\u003e\u003c/h4\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../status.png" alt="Geoguessr Compass"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eThe Geoguessr Status displays three information:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eUnder \u003cstrong\u003eMap\u003c/strong\u003e is displayed the current Map.\u003c/p\u003e\n\u003cp\u003eFor example: \u003cstrong\u003e\u0026ldquo;World\u0026rdquo;\u003c/strong\u003e.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eUnder \u003cstrong\u003eRound\u003c/strong\u003e is displayed the current round.\u003c/p\u003e\n\u003cp\u003eA round of Geoguessr last five rounds.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eUnder \u003cstrong\u003eScore\u003c/strong\u003e is displayed the current score.\u003c/p\u003e\n\u003cp\u003eThe maximum score in a game of Geoguessr is 25000, with 5000 points per round.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch4 id="map-a-idmap"\u003eMap \u003ca id="map"/\u003e\u003c/h4\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../map_before.png" alt="Geoguessr Map when non-expanded"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../map_after.png" alt="Geoguessr Map when expanded"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eThe Geoguessr Map displays Google Maps in a small window. The player is free to zoom in and zoom out of the Map to figure out their whereabouts. They can then click anywhere to put down their guessed location.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eThe \u003cimg src="../../zoom_in.png"\u003e allows the player to zoom in the Map. The \u003cimg src="../../zoom_out.png"\u003e allows the player to zoom out in the Map.\u003c/li\u003e\n\u003cli\u003eThe \u003cimg src="../../increase_size.png"\u003e allows the player to make the Map window bigger, while \u003cimg src="../../decrease_size.png"\u003e allows the player to make the Map smaller.\u003c/li\u003e\n\u003cli\u003eThe \u003cimg src="../../sticky_map.png"\u003e allows the player to keep the Map window in its expanded state. The \u003cimg src="../../sticky_map_left.png"\u003e allows the player to make the Map window non-expanded again.\u003c/li\u003e\n\u003c/ul\u003e\n\u003cp\u003eBelow the Map, the \u003cstrong\u003eGuess\u003c/strong\u003e button allows the player to submit their location.\u003c/p\u003e\n\u003ch4 id="panorama-a-idpanorama"\u003ePanorama \u003ca id="panorama"/\u003e\u003c/h4\u003e\n\u003cp\u003eThe Panorama is a feature of Google MapsMapillary, called Street View. It allows the player to roam through \u0026hellip;\u003c/p\u003e\n\u003ch4 id="movement-arrows-a-idarrows"\u003eMovement arrows \u003ca id="arrows"/\u003e\u003c/h4\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../movement_arrows.png" alt="Geoguessr Movement arrows"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eThe Movement arrows are a feature of Google MapsMapillary, which allows the player to navigate through the Panorama in the direction they\u0026rsquo;re facing.\u003c/p\u003e\n\u003cp\u003eOnce clicked, the Panorama changes to the next available image.\u003c/p\u003e\n\u003ch3 id="recognizing-your-location-through-language"\u003eRecognizing your location through language\u003c/h3\u003e\n\u003cp\u003eMost often than not, the fastest way to recognize where you are is to read a sign.\u003c/p\u003e\n\u003cp\u003eLet\u0026rsquo;s compare a few languages.\u003c/p\u003e\n\u003ch3 id="geography"\u003eGeography\u003c/h3\u003e\n\u003ch3 id="miscellaneous-meta-clues"\u003eMiscellaneous (meta clues)\u003c/h3\u003e\n\u003cp\u003eThe nature of imagery makes it that by country, or region, meta clues can be spotted.\u003c/p\u003e\n\u003ch2 id="i-cant-play-geoguessr"\u003eI can\u0026rsquo;t play Geoguessr!\u003c/h2\u003e\n\u003cp\u003eHere are a few issues reported by our readers while playing Geoguessr, and our solutions.\u003c/p\u003e\n\u003ch3 id="the-geoguessr-panorama-displays-a-black-screen"\u003eThe Geoguessr Panorama displays a black screen\u003c/h3\u003e\n\u003cp\u003egeoguessr only shows me a black screen, aaaaaaaggghhhh!!!!!!!!\u003c/p\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../black_screen.png" alt="Geoguessr shows me a black screen"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eDo not worry, this is a common bug due to insufficient connection speed, try the following course of action:\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003eBegin by refreshing your tab.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003e\n\u003cp\u003eOn Windows, in most web browsers (including Google Chrome, Mozilla Firefox and Microsoft Edge), you will find this feature in the top left-hand corner of the screen, next to the \u003cstrong\u003eBack\u003c/strong\u003e and \u003cstrong\u003eForward\u003c/strong\u003e buttons.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eOn Mac OS, however, in Safari you will find it on the right-side of the \u003cstrong\u003eSearch\u003c/strong\u003e bar.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003cdiv class="alert alert-warning d-flex" role="alert"\u003e\r\n  \u003cdiv class="flex-shrink-1 alert-icon"\u003e👉 \u003c/div\u003e\r\n  \r\n    \u003cdiv class="w-100"\u003eYou can also press F5 or CTRL+R on Windows, or Command+R on Mac OS. \u003c/div\u003e\r\n  \r\n\u003c/div\u003e\r\n\n\u003c!-- markdownlint-disable MD029 --\u003e\n\u003col start="2"\u003e\n\u003cli\u003eIf this doesn\u0026rsquo;t solve your issue, consider reading \u003ca href="#no_network"\u003eGeoguessr is inaccessible\u003c/a\u003e.\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch3 id="geoguessr-is-inaccessible-a-idno_network"\u003eGeoguessr is inaccessible \u003ca id="no_network"/\u003e\u003c/h3\u003e\n\u003c!-- markdownlint-disable MD029 MD030 --\u003e\n\u003cp\u003ei can\u0026rsquo;t reach geoguessr.com anymore! pls halp!\u003c/p\u003e\n\u003cbr/\u003e\n\u003cdiv style="text-align: center;"\u003e\u003cimg src="../../no_network.png" alt="Geoguessr doesn\'t load"\u003e\u003c/div\u003e\n\u003cbr/\u003e\n\u003cp\u003eIt seems you\u0026rsquo;re not connected to the Internet anymore, try the following course of action:\u003c/p\u003e\n\u003col\u003e\n\u003cli\u003e\n\u003cp\u003eBegin by checking your \u003cstrong\u003eNetwork\u003c/strong\u003e settings.\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eOn Windows, go to \u003cstrong\u003eStart Menu\u003c/strong\u003e \u0026gt; \u003cstrong\u003eSettings\u003c/strong\u003e \u0026gt; \u003cstrong\u003eNetwork \u0026amp; internet\u003c/strong\u003e.\u003c/li\u003e\n\u003cli\u003eOn Mac OS, go to \u003cstrong\u003eApple menu\u003c/strong\u003e \u0026gt; \u003cstrong\u003eSystem Preferences\u003c/strong\u003e \u0026gt; \u003cstrong\u003eNetwork\u003c/strong\u003e.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eIf you\u0026rsquo;re indeed disconnected, try the following course of action:\u003c/p\u003e\n\u003cul\u003e\n\u003cli\u003eIf you\u0026rsquo;re connected through \u003cstrong\u003eWifi\u003c/strong\u003e, try turning off then on the \u003cstrong\u003eWifi\u003c/strong\u003e option.\u003c/li\u003e\n\u003cli\u003eIf you\u0026rsquo;re connected through ethernet, try removing the cable from your computer then plugging it in again.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eIf this doesn\u0026rsquo;t solve your issue, try turning your computer off then on.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eIf this doesn\u0026rsquo;t solve your issue, go check your router.\u003c/p\u003e\n\u003cp\u003eA red blinking red light might be sign of a problem with the router\u0026rsquo;s connection.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eIf it does seem to be malfunctioning, try turning it off and on.\u003c/p\u003e\n\u003c/li\u003e\n\u003cli\u003e\n\u003cp\u003eIf after rebooting the issue persists, try calling your ISP or go see your local IT shop.\u003c/p\u003e\n\u003c/li\u003e\n\u003c/ol\u003e\n\u003ch2 id="conclusion"\u003eConclusion\u003c/h2\u003e\n\u003ch3 id="competitive-geoguessr-get-gud"\u003eCompetitive Geoguessr (get gud)\u003c/h3\u003e\n\u003ch3 id="more-ressources"\u003eMore ressources\u003c/h3\u003e\n'}).add({id:3,href:"/en/docs/edu/uni-lille/",title:"Université de Lille",description:"September 2015 to September 2018 - Bachelor of Arts in English Studies",content:'\u003cimg src="../../lille_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:69px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description"\u003eDescription\u003c/h2\u003e\n\u003cp\u003eDeep learning of English: how to speak it (through phonetics and exchanges with native professors), how to write it (grammar) and how to better understand it (history and literature).\u003c/p\u003e\n\u003ch2 id="erasmus---universitat-de-valència"\u003eErasmus - Universitat de València\u003c/h2\u003e\n\u003cp\u003eSeptember 2017 to September 2018 - EN\u0026gt;ES translation.\u003c/p\u003e\n\u003cimg src="../../valencia_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:69px; max-height:69px;  width: auto;  height: auto;"\u003e\n'}).add({id:4,href:"/en/docs/cv/talend/",title:"Talend",description:"September 2021 to September 2022 - Apprenticeship in technical writing",content:'\u003cimg src="../../talend_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:69px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description-of-tasks"\u003eDescription of tasks\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eTechnical writing in DITA, managed through Git (e.g. updates to the internal localization guidelines of documentation and products).\u003c/li\u003e\n\u003cli\u003eCreation of \u0026ldquo;how-to\u0026rdquo; software tutorials.\u003c/li\u003e\n\u003cli\u003eEN\u0026gt;FR translation.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="tools-used"\u003eTools used\u003c/h2\u003e\n\u003ctable style="table-layout: fixed; width: 100%;"\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd colspan="2"\u003e\u003cb\u003eWriting\u003c/b\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../git_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:34px; max-height:34px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eGit\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../dita_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:24px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eDITA\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="https://www.oxygenxml.com/img/resources/oxygen190x62.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:68px; max-height:22px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eOxygenXML\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../md_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:24px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eMarkdown\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ctable style="table-layout: fixed; width: 100%;"\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd colspan="2"\u003e\u003cb\u003eCommunication\u003c/b\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../jira_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:100px; max-height:60px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eJIRA\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../slack_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:80px; max-height:60px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eSlack\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n'}).add({id:5,href:"/en/docs/cv/t4e/",title:"Trans4europe",description:"June 2020 to August 2021 - Translation project management",content:'\u003cimg src="../../t4e_logo.png" alt=" slice atop a pile of other slices" style="max-width:100px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description-of-tasks"\u003eDescription of tasks\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eOrganization and management of multilingual translation projects.\u003c/li\u003e\n\u003cli\u003eAnalysis and preparation of work packages for CAT tools.\u003c/li\u003e\n\u003cli\u003eManagement of ~20 internal translators as well as freelance translators.\u003c/li\u003e\n\u003cli\u003eCorrespondence with our clients\' project managers.\u003c/li\u003e\n\u003cli\u003eTranslation quality monitoring.\u003c/li\u003e\n\u003cli\u003eManagement of a shared email inbox.\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="tools-used"\u003eTools used\u003c/h2\u003e\n\u003ctable style="table-layout: fixed; width: 100%;"\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd colspan="2"\u003e\u003cb\u003eCAT tools\u003c/b\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../trados_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eTrados Studio\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../memoq_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eMemoQ\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../memsource_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:68px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eMemsource\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../xtm_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:60px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eXTM\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n\u003ctable style="table-layout: fixed; width: 100%;"\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd colspan="2"\u003e\u003cb\u003eProject management\u003c/b\u003e\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../projetex_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:35px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eProjetex\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../skype_logo.jpg" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eSkype\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n'}).add({id:6,href:"/en/docs/cv/inra/",title:"INRA",description:"March 2019 to June 2019 - Internship in scientific translation",content:'\u003cimg src="../../inra_logo.jpg" alt=" slice atop a pile of other slices" style="max-width:100px; max-height:69px;  width: auto;  height: auto;"\u003e\n\u003ch2 id="description-of-tasks"\u003eDescription of tasks\u003c/h2\u003e\n\u003cul\u003e\n\u003cli\u003eScientific translation and terminology for the ATOL ontology (atol-ontology.com).\n\u003cul\u003e\n\u003cli\u003eEnglish to French translation of the names and definitions of the phenotypical traits of livestock.\u003c/li\u003e\n\u003c/ul\u003e\n\u003c/li\u003e\n\u003c/ul\u003e\n\u003ch2 id="tools-used"\u003eTools used\u003c/h2\u003e\n\u003ctable style="table-layout: fixed; width: 100%;"\u003e\n\u003ctbody\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../excel_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:67px; max-height:30px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eMicrosoft Excel\u003c/td\u003e\n\u003c/tr\u003e\n\u003ctr\u003e\n\u003ctd\u003e\u003cimg src="../../vba_logo.png" alt="Grapefruit slice atop a pile of other slices" style="max-width:90px; max-height:70px;  width: auto;  height: auto;"\u003e\u003c/td\u003e\n\u003ctd\u003eMacros (VBA)\u003c/td\u003e\n\u003c/tr\u003e\n\u003c/tbody\u003e\n\u003c/table\u003e\n'}).add({id:7,href:"/en/docs/cv/",title:"jobs",description:"Help Doks.",content:""}).add({id:8,href:"/en/docs/edu/",title:"Resume",description:"Resume",content:""}).add({id:9,href:"/en/docs/portfolio/",title:"Resume",description:"Resume",content:""}).add({id:10,href:"/en/docs/",title:"Docs",description:"Docs Doks.",content:""}),search.addEventListener('input',b,!0),suggestions.addEventListener('click',c,!0);function b(){var d,e;const c=5;d=this.value,e=a.search(d,{limit:c,enrich:!0}),suggestions.classList.remove('d-none'),suggestions.innerHTML="";const b={};e.forEach(a=>{a.result.forEach(a=>{b[a.doc.href]=a.doc})});for(const d in b){const e=b[d],a=document.createElement('div');if(a.innerHTML='<a href><span></span><span></span></a>',a.querySelector('a').href=d,a.querySelector('span:first-child').textContent=e.title,a.querySelector('span:nth-child(2)').textContent=e.description,suggestions.appendChild(a),suggestions.childElementCount==c)break}}function c(){while(suggestions.lastChild)suggestions.removeChild(suggestions.lastChild);return!1}})()